export interface ParseResultDTO {
  rawText: string;
  normalizedText: string;
  parsedCharacters: Array<{ characterId: number; name: string }>;
  candidateNames: string[];
  invalidLines: Array<{ line: string; reasonCode: string }>;
  warnings: Array<{ provider: string; code: string; message: string }>;
  inputKind: string;
  confidence: number;
  removedDuplicates: number;
  suspiciousArtifacts: number;
  parsedAt: string;
}

export interface AnalysisSessionDTO {
  sessionId: string;
  createdAt: string;
  updatedAt: string;
  source: ParseResultDTO;
  pilots: unknown[];
  warnings: Array<{ provider: string; code: string; message: string }>;
}

export function AnalyzePastedText(text: string): Promise<AnalysisSessionDTO> {
  return Promise.resolve({
    sessionId: `session-${Date.now()}`,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    source: {
      rawText: text,
      normalizedText: text,
      parsedCharacters: [],
      candidateNames: [],
      invalidLines: [],
      warnings: [],
      inputKind: 'unknown',
      confidence: 0,
      removedDuplicates: 0,
      suspiciousArtifacts: 0,
      parsedAt: new Date().toISOString(),
    },
    pilots: [],
    warnings: [{ provider: 'bootstrap', code: 'PLACEHOLDER', message: 'analysis pipeline not yet connected' }],
  });
}

export function RefreshSession(sessionId: string): Promise<AnalysisSessionDTO> {
  return AnalyzePastedText(sessionId);
}

